const d = $input.item.json.body || $input.item.json;
const montant = parseFloat(d.montant);
if (!montant || montant <= 0 || montant > 50000) throw new Error('Montant invalide');
const clean = (s, max) => (s || '').toString().replace(/<[^>]*>/g, '').trim().substring(0, max);
const cats = ['alimentation','transport','logement','sante','loisirs','shopping','restauration','abonnements','autre'];
const cat = cats.includes((d.categorie || '').toLowerCase()) ? d.categorie.toLowerCase() : 'autre';
const dateStr = d.date ? new Date(d.date).toISOString().split('T')[0] : new Date().toISOString().split('T')[0];
return { montant, categorie: cat, description: clean(d.description, 200), date: dateStr, source: 'webhook' };

const totaux = $input.all().map(i => i.json);
const totalMois = totaux.reduce((s, r) => s + parseFloat(r.total || 0), 0);
const budget = parseFloat($env.BUDGET_MENSUEL_ALERTE) || 2000;
const depense = $('Valider dépense').item.json;
return [{
  json: {
    totaux,
    total_mois: totalMois.toFixed(2),
    budget_mensuel: budget,
    depassement: totalMois > budget,
    pct_budget: Math.round(totalMois / budget * 100),
    derniere_depense: depense
  }
}];
